import{_ as n,C as p,o as _,c as i,a3 as o,E as r,w as d,j as t,a as e}from"./chunks/framework.CH_GxKL1.js";const T=JSON.parse('{"title":"","description":"","frontmatter":{"indexDrivenFooter":{"parent":{"text":"Taming Your Amygdala","link":"/readings/Taming_Your_Amygdala/"},"prev":{"text":"Taming Your Amygdala","link":"/readings/Taming_Your_Amygdala/"},"next":{"text":"ch02 - 认识你的杏仁核","link":"/readings/Taming_Your_Amygdala/contexts/Chapter 02 - 认识你的杏仁核"}},"prev":{"text":"Taming Your Amygdala","link":"/readings/Taming_Your_Amygdala/"},"next":{"text":"ch02 - 认识你的杏仁核","link":"/readings/Taming_Your_Amygdala/contexts/Chapter 02 - 认识你的杏仁核"}},"headers":[],"relativePath":"readings/Taming_Your_Amygdala/contexts/Chapter 01 - 理解焦虑.md","filePath":"readings/Taming_Your_Amygdala/contexts/Chapter 01 - 理解焦虑.md","lastUpdated":1782737468000}'),h={name:"readings/Taming_Your_Amygdala/contexts/Chapter 01 - 理解焦虑.md"};function s(u,a,m,g,c,x){const l=p("SplitNoteInsert");return _(),i("div",null,[a[2]||(a[2]=o('<h2 id="title" tabindex="-1">第一章：理解焦虑 <a class="header-anchor" href="#title" aria-label="Permalink to &quot;第一章：理解焦虑 {#title}&quot;">​</a></h2><p>每个人都经历过焦虑。 但很少有人理解焦虑的真正本质，也不了解焦虑与大脑中那些名称难拼、更遑论理解的情绪产生结构有何关联。 本书旨在帮助你更深入地了解大脑中这些至关重要的部分，尤其是杏仁核。 无论你患有创伤后应激障碍（PTSD）、强迫症（OCD）、恐惧症、广泛性焦虑障碍，还是任何其他焦虑障碍，杏仁核都在制造你所经历的焦虑中扮演着核心角色。</p><p>当你被焦虑、恐慌或忧虑困扰时，别人往往不理解你正在经历什么。 你自己甚至也可能不理解。 焦虑可能是一种非常令人难以承受且困惑的体验。 好消息是，与许多其他心理障碍相比，心理健康专业人士对焦虑障碍的理解更为深入，而且一旦你学会了在经历焦虑时识别出大脑中正在发生什么，你也就知道该如何应对你的焦虑了。</p><p>本书将帮助你解读你的大脑和身体中正在发生什么（以及这些过程为什么会发生）。 有了这些知识，你将能够更好地应对你所经历的一切。 即使别人告诉你，你的行为、感受和想法说不通，本书也会帮助你理解它们，而你自己才是最重要的那个人。 我的许多来访者在了解到大脑如何制造焦虑时都说：&quot;原来是这么回事！&quot; 能够弄明白正在发生什么，可以带来巨大的解脱。</p><p>但光有知识还不够。 你还需要知道你能用这些知识做什么。 你可以改变大脑中制造焦虑的结构，但实现这种改变需要你采取一种新的方式来回应你的焦虑和忧虑。 这就是你需要这本书的原因 -- 它不仅旨在帮助你理解你基于焦虑的困难，还为你提供具体的工具和步骤来训练你的大脑以不同的方式做出反应。</p><p>是的，你可以改变你的焦虑。 我不能保证你过上完全没有焦虑的生活；没有哪个健康的人能做到百分之百摆脱焦虑或恐惧，而且这也不是什么好事。 （我个人可不想跟毫无焦虑的司机一起上路！） 我能做的是帮助你明确你生活中的目标，并为你提供所需的工具，确保焦虑和忧虑不会阻碍你实现这些目标。 而这正是本书将引导你完成的。 到本书结束时，你将对焦虑的意义和目的以及如何有效管理焦虑有更深入的理解。</p><p>许多人都熟悉&quot;焦虑&quot;这个词，但他们可能不知道焦虑在人们生活中出现的各种不同形式。 有的人感到恶心，有的人颤抖，有的人头痛，还有的人只想逃离。 虽然我们每个人体验焦虑的方式都独一无二，但焦虑的根源是相同的：<strong>杏仁核</strong>。 这是你大脑中控制焦虑或恐惧反应的部分。 如果你想管理你的焦虑，杏仁核就是大脑中最需要理解的部分。 尽管杏仁核产生的反应旨在保护你，但这些反应可能与情况并不匹配。 这些反应大多让你的身体准备好与潜在的捕食者或威胁搏斗或逃离，但在二十一世纪，搏斗和逃离往往是不恰当的反应。 幸运的是，焦虑或恐惧反应的某些方面是可以改变的。 在本书中，你将学到多种方法来驯服你的杏仁核，从而改变你的焦虑。</p><h3 id="h3-1" tabindex="-1">评估你的焦虑 <a class="header-anchor" href="#h3-1" aria-label="Permalink to &quot;评估你的焦虑 {#h3-1}&quot;">​</a></h3><p>如果你想改变你的焦虑，你可以采取的第一步就是测量它。 这样，你就能更好地识别你的焦虑，并观察它在不同日子和不同情境下如何变化。 在某些情境和某些日子里，焦虑会更强，如果你持续追踪，或许能够辨别出它为什么变化。 你还会对你的焦虑的不同维度有更好的理解。 测量你的焦虑可以帮助你更加觉察当杏仁核激活焦虑或恐惧反应时你的身体正在发生什么，这将在以下几个方面对你有所帮助：</p><p>更加觉察你具体的焦虑症状可以帮助你管理你对它们的反应。 焦虑被设计成一种不舒服和令人痛苦的体验，所以人们很容易只是消极地对其做出反应，而没有觉察。 你可能没有注意到你背部和肩膀的肌肉非常紧张，或者没有意识到你的头痛是由肌肉紧张引起的。 你也可能误解读恶心的感觉，认为自己是生病了，而不是焦虑了。 意识到焦虑的身体层面将使你能够更好地控制你对焦虑的反应，并为你打开更多控制焦虑反应本身的机会。</p><p>识别你的具体症状可以帮助你认识到隐藏在它们背后的进化目的，并将它们正常化。 焦虑是一种进化上具有适应性的防御反应的一部分，这种反应的设计有一个重要的目的：保护我们免受危险。 这种防御反应（也称为应激反应）通过促使我们的祖先逃离、搏斗或躲避野生动物或其他捕食者来保护他们免受危险。 没有恐惧或忧虑的人不太可能生存下来，也不太可能确保他们的孩子生存下来。 因此，今天活着的人类很可能是那些恐惧的人的后代，而不是那些冷静的人的后代！ 尽管我们在现代生活中面临的大多数问题已经不同，但我们仍然拥有那种内置的防御反应，它制造焦虑。 对你所经历的症状有更多的觉察，将帮助你注意到焦虑反应的进化益处在你许多症状中的反映。 例如，当你焦虑时，你的心脏可能会怦怦直跳。 当你理解杏仁核正在通过更强劲地将血液泵入你的手臂和腿部来让身体准备逃跑时，这就说得通了。 尽管焦虑可能令人痛苦，但它是人类大脑的正常运作。 每个人在某种程度上都有焦虑，目标不是完全消除它，而是确保它不限制你的人生。</p><p>认识到你的焦虑如何随不同情境而变化，可以帮助你准确定位你的焦虑触发因素，并识别其他有用的因素。 每个人的焦虑都在时时刻刻变化，也在日复一日地变化。 通过反复测量你的焦虑症状，你可以开始认识到你的焦虑与某些触发因素有关，比如特定的声音、情境或想法。 你生活中的某些方面，比如睡眠和运动，也会影响你的焦虑。 你还可能注意到你的焦虑往往在一天中的某些时间出现。 通过测量你的焦虑症状在频率和强度上的波动，你可以培养对影响你焦虑的各种因素的觉察。</p><p>在下一页，你会找到一个工作表，为你提供一种快速评估焦虑的方法。 请每天填写几次，持续一周左右，以了解你是如何体验焦虑的。 请记住，没有人体验焦虑的方式与你完全相同。 尽管焦虑有一些共同的方面，但每个人的体验都不同。</p><h3 id="h3-2" tabindex="-1">WORKSHEET: 评估你的焦虑 <a class="header-anchor" href="#h3-2" aria-label="Permalink to &quot;WORKSHEET: 评估你的焦虑 {#h3-2}&quot;">​</a></h3><p>本调查是汉密尔顿焦虑评定量表（Maier et al., 1988）的改编版；你可以用它来测量你的焦虑，并更好地了解你的具体焦虑症状。 焦虑不仅仅关乎你的情绪，这份调查将焦虑分解为几个可能影响你的不同维度。 它将帮助你更加熟悉你的焦虑的不同方面，也许还会让你感到不那么被这些方面所淹没。 有些症状可能会让你吃惊，因为你可能没有意识到它们可能与焦虑有关。</p><p>使用以下量表来评定你当前焦虑每个方面的强度。 在调查结束时，你将把分数相加，得到你当前焦虑的总体评分。</p><p>0 = 不存在</p><p>1 = 轻度</p><p>2 = 中度</p><p>3 = 重度</p><p>_____ 1. 焦虑情绪（忧虑、预期最坏情况、恐惧预期、易激惹）</p><p>_____ 2. 紧张（肌肉紧绷、疲劳、惊跳反应、易流泪、颤抖、坐立不安、无法放松）</p><p>_____ 3. 恐惧（对黑暗、陌生人、独处、动物、昆虫、交通、人群、疾病等的恐惧）</p><p>_____ 4. 失眠（入睡困难、睡眠中断、早醒、睡眠不满意及醒来时疲劳、做梦、噩梦、夜惊）</p><p>_____ 5. 智力影响（注意力难以集中、聚焦困难、记忆力差）</p><p>_____ 6. 抑郁情绪（兴趣丧失、爱好中缺乏愉悦感、悲伤、情感麻木、早醒、早晨感觉更糟）</p><p>_____ 7. 躯体/肌肉症状（疼痛和酸痛、抽搐、僵硬、肌肉跳动、磨牙、声音不稳、肌张力增高）</p><p>_____ 8. 躯体/感觉症状（耳鸣、视力模糊、冷热发作、虚弱感、针刺感、头晕、金属味）</p><p>_____ 9. 心血管症状（心跳加快、心悸、心颤、血管搏动、胸部疼痛感、漏跳）</p><p>_____ 10. 呼吸症状（胸部压迫感或紧缩感、窒息感、叹气、呼吸困难、倾向于屏住呼吸）</p><p>_____ 11. 胃肠症状（吞咽困难、腹痛、烧灼感、腹胀、恶心、呕吐、腹鸣、便稀、腹泻、体重减轻、便秘）</p><p>_____ 12. 泌尿生殖症状（尿频、尿急、闭经、经量过多或经期延长、性高潮困难、早泄、对性失去兴趣、维持勃起或射精困难）</p><p>_____ 13. 自主神经症状（口干、脸红、苍白、出汗倾向、头晕、紧张性头痛、汗毛竖立）</p><p>_____ 14. 行为（坐立不安、烦躁或踱步、手抖、眉头紧锁、面部紧绷、叹气或呼吸急促、反复吞咽、回避）</p><p>现在将你在14个项目中所填写的所有数字相加。 这将得出你对此情境/时间的总体焦虑评分：_____</p><h3 id="你的焦虑分数告诉你什么" tabindex="-1">你的焦虑分数告诉你什么？ <a class="header-anchor" href="#你的焦虑分数告诉你什么" aria-label="Permalink to &quot;你的焦虑分数告诉你什么？&quot;">​</a></h3><p>0～13</p><p>极轻度焦虑</p><p>14～21</p><p>轻度至中度焦虑</p><p>22～35</p><p>中度至重度焦虑</p><p>36～42</p><p>重度焦虑</p><hr><p>Copyright � 2022 Catherine M. Pittman. Taming Your Amygdala. All rights reserved.</p><hr><p>建议每天使用焦虑量表不止一次，并养成记录每次评分的日期和时间的习惯。 记录你完成量表时正在发生什么也很有帮助，这样你就能更加觉察是什么触发了你的焦虑。 诸如此类的细节使记录更有用。 你可能想要准备一本个人日记，这样你就有足够的空间来记录你的焦虑评分（以及其他有用的笔记），或者你可以复印下一页提供的每日焦虑记录表。</p><p>如果你对监测焦虑不感兴趣，或者你发现过多的评估会增加你的焦虑，你不需要保留这个记录超过一周左右。 不过，我鼓励你在学习本书中的各种练习和工具时，定期重新进行这项评估。 当你开始尝试不同的应对策略时，保留这个记录将使你能够看到不同的策略如何影响你的焦虑评分，以及你进步了多少，这样你就能判断哪些工具在减轻焦虑方面最有效。</p><h2 id="worksheet-每日焦虑记录" tabindex="-1">WORKSHEET: 每日焦虑记录 <a class="header-anchor" href="#worksheet-每日焦虑记录" aria-label="Permalink to &quot;WORKSHEET: 每日焦虑记录&quot;">​</a></h2><p>使用此工作表来追踪你的焦虑评分随时间的变化，并记下与你的焦虑相关的任何潜在触发因素。 请务必使用&quot;评估你的焦虑&quot;工作表中的调查来计算你每次焦虑的评分。</p><p>下面先为你提供了一个示例，随后是一个空白模板，供你记录自己的焦虑评分。</p><table tabindex="0"><thead><tr><th>日期</th><th>时间</th><th>焦虑评分</th><th>触发因素或其他备注（当时正在发生什么？）</th></tr></thead><tbody><tr><td>10/25</td><td>晚上7:30</td><td>16</td><td>与伴侣进行了一次困难的对话；预期最坏情况（分手）</td></tr><tr><td>10/26</td><td>上午10:00</td><td>25</td><td>收到老板发来的一封关于意外工作任务的邮件</td></tr></tbody></table><table tabindex="0"><thead><tr><th>日期</th><th>时间</th><th>焦虑评分</th><th>触发因素或其他备注（当时正在发生什么？）</th></tr></thead><tbody><tr><td></td><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td><td></td></tr></tbody></table><hr><p>Copyright � 2022 Catherine M. Pittman. Taming Your Amygdala. All rights reserved.</p>',56)),r(l,{target:"title",until:"h3-1"},{default:d(()=>[...a[0]||(a[0]=[t("p",null,'第一章用了两个章节，介绍了看待"焦虑"的视角，也表明了本书讲如何围绕"焦虑"来组织内容。',-1),t("h3",{id:"关于-理解焦虑",tabindex:"-1"},[e('关于"理解焦虑" '),t("a",{class:"header-anchor",href:"#关于-理解焦虑","aria-label":'Permalink to "关于"理解焦虑""'},"​")],-1),t("ul",null,[t("li",null,'首先解读"焦虑发生时，大脑发生了什么"。'),t("li",null,'然后讲"如何使用这些知识应对焦虑"，通常而言，是新习惯。 也就是书中说的"采取一种新的方式来回应你的焦虑和忧虑"。'),t("li",null,[e('接着，作者强调了终极目的---"我能做的是帮助你明确你生活中的目标，并为你提供所需的工具，确保焦虑和忧虑不会阻碍你实现这些目标" --- 关键永远是有自己的人生目标，本书只是减少阻力的方法。 '),t("ul",null,[t("li",null,'最后更加深入的简单介绍了一下，"管理焦虑"本质上就是管理"杏仁核"。')])])],-1)])]),_:1}),r(l,{target:"h3-1",scope:"section"},{default:d(()=>[...a[1]||(a[1]=[t("h3",{id:"关于-评估焦虑",tabindex:"-1"},[e('关于"评估焦虑"： '),t("a",{class:"header-anchor",href:"#关于-评估焦虑","aria-label":'Permalink to "关于"评估焦虑"："'},"​")],-1),t("ul",null,[t("li",null,'不同于上文的抽象讨论，这里我们接触到了第一个"方法论" --- 评估。'),t("li",null,'同样是出于"聚焦目标"的目的，为了"管理焦虑"，我们首先要"评定焦虑等级"，"体验、识别焦虑"。')],-1),t("h3",{id:"评语",tabindex:"-1"},[e("评语 "),t("a",{class:"header-anchor",href:"#评语","aria-label":'Permalink to "评语"'},"​")],-1),t("p",null,[t("strong",null,"整体评价：结构清晰，抓住了本章两条主线，是一份不错的起步笔记。")],-1),t("p",null,"几点具体反馈：",-1),t("p",null,[t("strong",null,"做得好的地方：")],-1),t("ul",null,[t("li",null,'将章节拆分为"理解焦虑"和"评估焦虑"两块，与原文结构对应得很好'),t("li",null,"引用了书中的关键原话（目标导向那段），这是很好的笔记习惯——方便日后回顾时快速触摸原文精神"),t("li",null,'抓住了"终极目的是人生目标，本书只是减阻工具"这个核心判断，说明你在主动提炼而非被动摘抄')],-1),t("p",null,[t("strong",null,"可以加强的地方：")],-1),t("ul",null,[t("li",null,'"第一章用了两个章节"应改为"第一章包含两个部分"或"两个小节"'),t("li",null,'遗漏了几个值得记的关键点：焦虑的进化意义（防御反应保护祖先生存）、"零焦虑不健康也不现实"的论点、杏仁核反应未必适应当代生活（战斗/逃跑在 21 世纪常不管用）'),t("li",null,'两个 WORKSHEET（焦虑评估量表 + 每日焦虑记录表）是本章的实操产出，笔记中提到了"评估"但没具体提及这两个工具，建议补一句'),t("li",null,[e('可以考虑加一个"我的行动"条目，比如：'),t("em",null,"本周每天用焦虑量表自评 2 次，记录在每日焦虑表上"),e("——把阅读转化为实践")])],-1),t("p",null,[t("strong",null,"一句话总结你的笔记质量：抓住了骨架，还差一点血肉。")],-1)])]),_:1})])}const y=n(h,[["render",s]]);export{T as __pageData,y as default};
